#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="H:\SE\node_modules\.pnpm\next@16.2.10_@babel+core@7._0ec1ef0512d9b2d448016207bbff1add\node_modules\next\node_modules;H:\SE\node_modules\.pnpm\next@16.2.10_@babel+core@7._0ec1ef0512d9b2d448016207bbff1add\node_modules;H:\SE\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/h/SE/node_modules/.pnpm/next@16.2.10_@babel+core@7._0ec1ef0512d9b2d448016207bbff1add/node_modules/next/node_modules:/mnt/h/SE/node_modules/.pnpm/next@16.2.10_@babel+core@7._0ec1ef0512d9b2d448016207bbff1add/node_modules:/mnt/h/SE/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../next/dist/bin/next" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../next/dist/bin/next" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../next/dist/bin/next" $args
  } else {
    & "node$exe"  "$basedir/../next/dist/bin/next" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
